func (s *GameServer) hasPermission(client *Client, requiredRole UserRole) bool {
	client.mu.RLock()
	defer client.mu.RUnlock()

	roleOrder := map[UserRole]int{
		UserRoleGuest:   0,
		UserRoleUser:    1,
		UserRoleModerator: 2,
		UserRoleAdmin:   3,
	}

	return roleOrder[client.role] >= roleOrder[requiredRole]
}

func (s *GameServer) authenticateClient(conn net.Conn, headers map[string]string) (*Client, error) {
	username := headers["username"]
	token := headers["token"]

	if username == "" || token == "" {
		return nil, fmt.Errorf("missing authentication data")
	}

	// Simulate token validation (in real app, validate against secure store)
	expectedToken := fmt.Sprintf("%s:%s", username, s.adminKey)
	if subtle.ConstantTimeCompare([]byte(token), []byte(expectedToken)) != 1 {
		return nil, fmt.Errorf("invalid token")
	}

	// Determine role based on username (in real app, fetch from secure store)
	role := UserRoleUser
	if strings.HasPrefix(username, "mod_") {
		role = UserRoleModerator
	} else if strings.HasPrefix(username, "admin_") {
		role = UserRoleAdmin
	}

	client := &Client{
		conn:     conn,
		username: username,
		role:     role,
	}

	return client, nil
}

func (s *GameServer) handleClient(conn net.Conn) {
	defer conn.Close()

	headers := make(map[string]string)
	scanner := bufio.NewScanner(conn)
	
	for scanner.Scan() {
		line := scanner.Text()
		if strings.HasPrefix(line, "Header:") {
			parts := strings.SplitN(line[7:], ":", 2)
			if len(parts) == 2 {
				headers[strings.TrimSpace(parts[0])] = strings.TrimSpace(parts[1])
			}
		} else {
			break
		}
	}

	client, err := s.authenticateClient(conn, headers)
	if err != nil {
		conn.Write([]byte("Authentication failed\n"))
		return
	}

	s.mu.Lock()
	s.clients[client] = true
	s.mu.Unlock()

	defer func() {
		s.mu.Lock()
		delete(s.clients, client)
		s.mu.Unlock()
	}()

	conn.Write([]byte("Connected to game server\n"))

	go func() {
		for {
			message, err := bufio.NewReader(conn).ReadString('\n')
			if err != nil {
				return
			}

			message = strings.TrimSpace(message)
			if strings.HasPrefix(message, "/") {
				s.processCommand(client, message)
			} else {
				s.broadcastMessage(client, message)
			}
		}
	}()

	// Keep connection alive
	select {}
}

func (s *GameServer) processCommand(client *Client, message string) {
	parts := strings.Fields(message)
	if len(parts) == 0 {
		return
	}

	commandName := parts[0]
	args := parts[1:]

	s.mu.RLock()
	cmd, exists := s.commands[commandName]
	s.mu.RUnlock()

	if !exists {
		client.conn.Write([]byte("Unknown command\n"))
		return
	}

	if !s.hasPermission(client, cmd.MinRole) {
		client.conn.Write([]byte("Insufficient permissions\n"))
		return
	}

	if err := cmd.Handler(client, args); err != nil {
		client.conn.Write([]byte(fmt.Sprintf("Error: %v\n", err)))
	}
}

func (s *GameServer) broadcastMessage(client *Client, message string) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	for c := range s.clients {
		if c != client {
			c.conn.Write([]byte(fmt.Sprintf("%s: %s\n", client.username, message)))
		}
	}
}

func (s *GameServer) Start(addr string) error {
	listener, err := net.Listen("tcp", addr)
	if err != nil {
		return err
	}
	defer listener.Close()

	fmt.Printf("Game server listening on %s\n", addr)

	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Printf("Accept error: %v\n", err)
			continue
		}

		go s.handleClient(conn)
	}
}

